    local OOll0ll00OO=(OllO00IlIOI-((OlIOO0OI0Ol+Ol00Olll0l0)%256))%256
    OO0I0llOIOl[Ol00Olll0l0]=string.char(OOI0lOIIO00(OOll0ll00OO,O0lO0OI000l))
end
local OOOlII0lIOO=table.concat(OO0I0llOIOl)
